        {"char": "晖", "pinyin": "hui", "origin": "小篆从日从军声。从日表与日光有关,军声。繁体为暉。", "primary": "本义为阳光、光辉。", "extended": "引申为晖映、春晖,又喻恩惠。", "usage": "春晖寸草、朝晖夕阴。"},
        {"char": "朗", "pinyin": "lang", "origin": "小篆从月从良声。从月表与月光有关,良有善义,合为月光明亮。", "primary": "本义为明亮。", "extended": "引申为明朗、爽朗、朗读,又指豁达。", "usage": "朗朗乾坤、豁然开朗。"},
        {"char": "曜", "pinyin": "yao", "origin": "小篆从日从翟声。从日表与日光有关,翟声。", "primary": "本义为日光。", "extended": "引申为日月星辰(七曜),又指照耀,又喻光芒耀眼。", "usage": "七曜星辰、光华曜目。"},
